def maximumTripletValue(self, nums):
    max_value = 0
    for i in range(0, len(nums), 3):
        for j in range(i+1, len(nums), 3):
            for k in range(j+1, len(nums), 3):
                curr_value = (nums[i] - nums[j]) * nums[k]
                max_value = max(max_value, curr_value)
    return max_value

